# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests

# Kong Admin API URL
KONG_ADMIN_URL = "http://localhost:8001"

# Service details
service_data = {
    "name": "my-service",
    "url": "http://my-service:8080"
}

# Route details
route_data = {
    "paths": ["/my-service"],
    "services": [{"id": None}]  # This will be updated later with the service ID
}

# Upstream and Target details
upstream_data = {
    "name": "my-upstream",
    "targets": [
        {"target": "127.0.0.1:8080"}
    ]
}

# Create upstream
response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
if response.status_code == 201:
    upstream_id = response.json()["id"]
    print(f"Upstream created with ID: {upstream_id}")
else:
    raise Exception("Failed to create upstream")

# Update route with the service ID
service_response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
if service_response.status_code == 201:
    service_id = service_response.json()["id"]
    print(f"Service created with ID: {service_id}")
else:
    raise Exception("Failed to create service")

route_data["services"][0]["id"] = service_id

# Create route
response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
if response.status_code == 201:
    print("Route created successfully")
else:
    raise Exception("Failed to create route")